import { createContext, type ReactNode, useContext, useState } from 'react';

interface SelectCtx {
  isOpen: boolean;
  value: string;
  open: () => void;
  close: () => void;
  select: (v: string) => void;
}

const SelectContext = createContext<SelectCtx | null>(null);

function useSelectCtx() {
  const ctx = useContext(SelectContext);
  if (!ctx) throw new Error('Select sub-components must be used inside <Select>');
  return ctx;
}

interface SelectProps {
  value: string;
  onChange: (value: string) => void;
  children: ReactNode;
}

function SelectRoot({ value, onChange, children }: SelectProps) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <SelectContext.Provider value={{
      isOpen,
      value,
      open: () => setIsOpen(true),
      close: () => setIsOpen(false),
      select: (v) => { onChange(v); setIsOpen(false); },
    }}>
      <div style={{ position: 'relative', display: 'inline-block' }}>{children}</div>
    </SelectContext.Provider>
  );
}

function Trigger() {
  const { value, open, isOpen } = useSelectCtx();
  return (
    <button
      type="button"
      onClick={open}
      style={{
        padding: '0.5rem 1rem',
        borderRadius: '0.375rem',
        border: '1px solid #d1d5db',
        background: '#fff',
        cursor: 'pointer',
        minWidth: '8rem',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        gap: '0.5rem',
      }}
    >
      <span>{value}</span>
      <span style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s' }}>▾</span>
    </button>
  );
}

function Options({ children }: { children: ReactNode }) {
  const { isOpen } = useSelectCtx();
  if (!isOpen) return null;
  return (
    <ul
      style={{
        position: 'absolute',
        top: '100%',
        left: 0,
        marginTop: '0.25rem',
        background: '#fff',
        border: '1px solid #d1d5db',
        borderRadius: '0.375rem',
        padding: '0.25rem',
        listStyle: 'none',
        minWidth: '8rem',
        boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
        zIndex: 10,
      }}
    >
      {children}
    </ul>
  );
}

function Option({ value, children }: { value: string; children: ReactNode }) {
  const { select, value: selected } = useSelectCtx();
  const isSelected = value === selected;
  return (
    <li
      onClick={() => select(value)}
      style={{
        padding: '0.375rem 0.625rem',
        borderRadius: '0.25rem',
        cursor: 'pointer',
        background: isSelected ? '#fef3c7' : 'transparent',
        fontWeight: isSelected ? 600 : 400,
      }}
    >
      {children}
    </li>
  );
}

export const Select = Object.assign(SelectRoot, { Trigger, Options, Option });
